const root = $input.first().json;
const agreements = root.entries ?? [];

if (!Array.isArray(agreements)) {
  throw new Error('Anchor agreements response did not include entries[]');
}

return agreements.map((agreement) => ({
  json: {
    relationshipId: agreement.id,
    listAgreement: agreement,
    sourceTotalCount: root.totalCount ?? null,
  },
}));

const lastSeenAt = new Date().toISOString();

function cleanNumber(value) {
  if (value === undefined || value === null || value === '') return null;
  const parsed = Number(value);
  return Number.isFinite(parsed) ? parsed : null;
}

function summarizeServices(services) {
  const summary = [];

  for (const service of services) {
    const children = Array.isArray(service.bundle?.services) ? service.bundle.services : [];
    summary.push({
      service_id: service.id ?? null,
      parent_service_id: null,
      service_template_id: service.serviceTemplateId ?? null,
      name: service.name ?? null,
      occurrence: service.billing?.occurrence ?? null,
      trigger: service.billing?.trigger ?? null,
      is_billed_upfront: service.billing?.isBilledUpfront ?? null,
      pricing_type: service.rate?.pricingType ?? null,
      price: cleanNumber(service.rate?.priceAfterDiscount ?? service.rate?.price),
      status: service.status?.type ?? null,
      is_paused: service.isPaused ?? null,
      is_bundle_parent: children.length > 0,
      is_bundle_child: false,
    });

    for (const child of children) {
      summary.push({
        service_id: child.id ?? null,
        parent_service_id: service.id ?? null,
        service_template_id: child.serviceTemplateId ?? null,
        name: child.name ?? null,
        occurrence: service.billing?.occurrence ?? null,
        trigger: service.billing?.trigger ?? null,
        is_billed_upfront: service.billing?.isBilledUpfront ?? null,
        pricing_type: service.rate?.pricingType ?? null,
        price: cleanNumber(child.rate),
        status: service.status?.type ?? null,
        is_paused: service.isPaused ?? null,
        is_bundle_parent: false,
        is_bundle_child: true,
      });
    }
  }

  return summary;
}

const rows = $input.all().map((item) => {
  const agreement = item.json;
  const services = Array.isArray(agreement.services) ? agreement.services : [];
  const serviceSummary = summarizeServices(services);

  return {
    anchor_relationship_id: agreement.id,
    agreement_name: agreement.agreementName ?? agreement.name ?? null,
    status: agreement.status ?? null,
    client_business_id: agreement.client?.business?.id ?? null,
    client_business_name: agreement.client?.business?.name ?? null,
    client_contact_id: agreement.client?.contactId ?? null,
    effective_date: agreement.effectiveDate ?? null,
    last_updated_at: agreement.lastUpdatedAt ?? null,
    raw: {
      ...agreement,
      profitSyncServiceSummary: serviceSummary,
    },
    last_seen_at: lastSeenAt,
  };
});

return [
  {
    json: {
      rowCount: rows.length,
      rows,
      sample: rows.slice(0, 3).map((row) => ({
        anchor_relationship_id: row.anchor_relationship_id,
        agreement_name: row.agreement_name,
        client_business_name: row.client_business_name,
        serviceCount: row.raw.profitSyncServiceSummary.length,
        bundleChildCount: row.raw.profitSyncServiceSummary.filter((service) => service.is_bundle_child).length,
      })),
    },
  },
];

const rows = $input.all().map((item) => item.json);

return [
  {
    json: {
      status: 'ok',
      upsertedCount: rows.length,
      sample: rows.slice(0, 5).map((row) => ({
        anchor_relationship_id: row.anchor_relationship_id,
        agreement_name: row.agreement_name,
        client_business_name: row.client_business_name,
        serviceCount: row.raw?.profitSyncServiceSummary?.length ?? 0,
      })),
    },
  },
];
